SELECT D.*, F.APPROVAL_FLAG AS TYPE_FLAG, (SELECT U.USER_NAME FROM PI_USER U WHERE U.USER_NO = D.USER_NO) AS USER_NAME, (SELECT U.SOSOK FROM PI_USER U WHERE U.USER_NO = D.USER_NO) AS USER_SOSOK, (SELECT U.USER_NAME FROM PI_USER U WHERE U.USER_NO = D.OK_USER_NO) AS OK_USER_NAME, (SELECT U.SOSOK FROM PI_USER U WHERE U.USER_NO = D.OK_USER_NO) AS OK_USER_SOSOK, IFNULL(SP.IDX,(SELECT IDX FROM pi_scan_policy WHERE OPEN='1')) AS POLICY_ID, IFNULL(SP.DATATYPE_ID,(SELECT DATATYPE_ID FROM pi_scan_policy WHERE OPEN='1')) AS DATATYPE_ID, IFNULL(A.AGENT_CORES, 3) AS CORES, L.LOCATION_ID FROM ((SELECT '1' AS TYPE, DPG.IDX, T.NAME, IF(SUBSTRING(T.PLATFORM, 1, 5) = 'Apple', SUBSTRING_INDEX(T.NAME, '.', -1), SUBSTRING_INDEX(T.NAME, '.', 1)) AS MAC_NAME, IF(SUBSTRING(T.PLATFORM, 1, 5) = 'Apple', SUBSTRING_INDEX(T.NAME, '.', 1), null) AS MAC_SERIAL, T.PLATFORM, DPG.TARGET_ID, DPG.data_processing_name AS FILENAME, DATE_FORMAT(DPG.REGDATE, '%Y-%m-%d %H:%i:%s') AS REGDATE, DATE_FORMAT(DP.DRDATE, '%Y-%m-%d %H:%i:%s') AS DRDATE, DATE_FORMAT(DPG.OKDATE, '%Y-%m-%d %H:%i:%s') AS OKDATE, DATE_FORMAT(DP.next_date_remedi, '%Y-%m-%d') AS REMEDIDATE, CASE WHEN DPG.APPROVAL_STATUS = 'E' THEN '완료' WHEN DPG.APPROVAL_STATUS = 'D' THEN '반려' WHEN DPG.APPROVAL_STATUS = 'W' THEN '대기' ELSE '' END APPROVAL_STATUS, DPG.APPROVAL_STATUS AS STATUS, DPG.REAPPROVAL_STATUS, CASE WHEN DPF.TYPE = 0 THEN DPG.REAPPROVAL_STATUS ELSE '-' END AS RESTATUS, DPG.NOTEPAD, DPG.USER_NO, DPG.OK_USER_NO, DP.AP_NO, DPG.RESEARCH_FLAG AS RESEARCH_FLAG, DPG.RESEARCH_FLAG AS RESEARCH, DPF.TYPE AS FLAG_TYPE FROM PI_DATA_PROCESSING_GROUP AS DPG LEFT OUTER JOIN PI_DATA_PROCESSING_FLAG DPF ON DPG.PROCESSING_FLAG = DPF.PROCESSING_FLAG LEFT OUTER JOIN pi_data_processing DP ON DP.DATA_PROCESSING_GROUP_IDX = DPG.IDX JOIN pi_targets T ON T.TARGET_ID = DPG.TARGET_ID AND T.ap_no = DP.ap_no WHERE 1=1
AND DP.PROCESSING_FLAG = #{processingFlag}
GROUP BY DPG.IDX ORDER BY DPG.REGDATE DESC, DPG.OKDATE DESC) UNION ALL (SELECT '4' AS TYPE, DPG.IDX, T.NAME, IF(SUBSTRING(T.PLATFORM, 1, 5) = 'Apple', SUBSTRING_INDEX(T.NAME, '.', -1), SUBSTRING_INDEX(T.NAME, '.', 1)) AS MAC_NAME, IF(SUBSTRING(T.PLATFORM, 1, 5) = 'Apple', SUBSTRING_INDEX(T.NAME, '.', 1), null) AS MAC_SERIAL, T.PLATFORM, DPG.TARGET_ID, DPG.path_ex_group_name AS FILENAME, DATE_FORMAT(DPG.REGDATE, '%Y-%m-%d %H:%i:%s') AS REGDATE, DATE_FORMAT(DP.DRDATE, '%Y-%m-%d %H:%i:%s') AS DRDATE, DATE_FORMAT(DPG.OKDATE, '%Y-%m-%d %H:%i:%s') AS OKDATE, '' AS REMEDIDATE, CASE WHEN DPG.APPROVAL_STATUS = 'E' THEN '완료' WHEN DPG.APPROVAL_STATUS = 'D' THEN '반려' WHEN DPG.APPROVAL_STATUS = 'W' THEN '대기' ELSE '' END APPROVAL_STATUS, DPG.APPROVAL_STATUS AS STATUS, '' AS REAPPROVAL_STATUS, '' AS RESTATUS, DPG.NOTEPAD, DPG.USER_NO, DPG.OK_USER_NO, DP.AP_NO, DPG.RESEARCH_FLAG AS RESEARCH_FLAG, DPG.RESEARCH_FLAG AS RESEARCH, -1 AS FLAG_TYPE FROM PI_PATH_EXCEPTION_GROUP AS DPG LEFT OUTER JOIN pi_path_exception DP ON DPG.IDX = DP.path_exception_group_idx LEFT OUTER JOIN PI_TARGETS AS T ON T.TARGET_ID = DPG.TARGET_ID AND DP.AP_NO = T.AP_NO GROUP BY DPG.IDX ORDER BY DPG.REGDATE DESC, DPG.OKDATE DESC) UNION ALL (SELECT DPG.FLAG+2 AS TYPE, DPG.IDX, T.NAME, IF(SUBSTRING(T.PLATFORM, 1, 5) = 'Apple', SUBSTRING_INDEX(T.NAME, '.', -1), SUBSTRING_INDEX(T.NAME, '.', 1)) AS MAC_NAME, IF(SUBSTRING(T.PLATFORM, 1, 5) = 'Apple', SUBSTRING_INDEX(T.NAME, '.', 1), null) AS MAC_SERIAL, T.PLATFORM, DPG.TARGET_ID, DPG.PATH AS FILENAME, DATE_FORMAT(DPG.REGDATE, '%Y-%m-%d %H:%i:%s') AS REGDATE, DATE_FORMAT(DPG.REGDATE, '%Y-%m-%d %H:%i:%s') AS DRDATE, DATE_FORMAT(DPG.OKDATE, '%Y-%m-%d %H:%i:%s') AS OKDATE, '' AS REMEDIDATE, CASE WHEN DPG.APPROVAL_STATUS = 'E' THEN '완료' WHEN DPG.APPROVAL_STATUS = 'D' THEN '반려' WHEN DPG.APPROVAL_STATUS = 'W' THEN '대기' ELSE '' END APPROVAL_STATUS, DPG.APPROVAL_STATUS AS STATUS, '' AS REAPPROVAL_STATUS, '' AS RESTATUS, DPG.REASON AS NOTE, DPG.REG_USER_NO AS USER_NO, DPG.OK_USER_NO, DPG.AP_NO, 0 AS RESEARCH_FLAG, 0 AS RESEARCH, -1 AS FLAG_TYPE FROM PI_CHARGE_UPDATE AS DPG JOIN PI_TARGETS AS T ON T.TARGET_ID = DPG.TARGET_ID AND T.AP_NO = DPG.AP_NO GROUP BY DPG.IDX ORDER BY DPG.REGDATE DESC, DPG.OKDATE DESC)) D LEFT OUTER JOIN PI_APPROVAL_FLAG F ON D.TYPE = F.IDX LEFT OUTER JOIN pi_scan_policy_server SPS ON SPS.target_id = D.TARGET_ID AND SPS.ap_no = D.AP_NO LEFT OUTER JOIN PI_SCAN_POLICY SP ON SPS.policy_id= SP.IDX LEFT OUTER JOIN pi_locations L ON D.TARGET_ID = L.TARGET_ID AND (L.DESCRIPTION REGEXP 'Catalog|All local files') AND D.AP_NO = L.AP_NO LEFT OUTER JOIN PI_AGENTS A ON A.AP_NO = D.AP_NO AND A.AGENT_NAME = D.NAME WHERE 1=1 AND DATE_FORMAT(D.REGDATE, '%Y-%m-%d') BETWEEN DATE_FORMAT(#{fromDate}, '%Y-%m-%d') AND DATE_FORMAT(#{toDate}, '%Y-%m-%d') AND (TYPE='0'
OR D.TYPE IN
#{item}
)
AND D.USER_NO = (#{user_no})
AND D.NAME LIKE CONCAT('%',#{owner},'%')
AND D.FILENAME LIKE CONCAT('%',#{filename},'%')
AND (D.STATUS IS NULL OR D.STATUS = '')
AND D.STATUS = #{status}
ORDER BY D.TYPE,D.REGDATE DESC, D.OKDATE DESC


SELECT IFNULL(COUNT(*), 0) + 1 AS SEQ
  FROM pi_data_processing_seq
 WHERE user_no = #{user_no}
   AND DATE_FORMAT(REGDATE,'%Y%m%d') = #{today}

SELECT D.* FROM ((SELECT 1 AS TYPE, DP.hash_id, DP.TARGET_ID, DPG.idx AS CHARGE_ID, (SELECT processing_flag_name FROM pi_data_processing_flag WHERE processing_flag = DP.processing_flag) AS FLAG, DP.user_no, DPG.data_processing_name, F.PATH,
CASE IFNULL(F.FID,'X') != 'X' WHEN 0 THEN 1 ELSE 0 END AS FID,
DP.AP_NO AS AP_NO, (SELECT T.NAME FROM pi_targets T WHERE T.TARGET_ID = DP.TARGET_ID AND T.AP_NO = DP.AP_NO) AS HOST_NAME
FROM PI_FIND AS F ,pi_data_processing AS DP ,pi_data_processing_group AS DPG WHERE 1=1 AND DP.target_id = F.target_id AND DP.group_id = F.group_id AND DP.hash_id = F.hash_id AND DP.AP_NO = F.AP_NO AND DPG.idx = DP.data_processing_group_idx AND DPG.target_id = DP.target_id AND DPG.idx = #{group_idx}) UNION ALL ( SELECT 4 AS TYPE, DP.hash_code AS hash_id, DP.TARGET_ID, DPG.idx AS CHARGE_ID, (SELECT path_ex_flag_name FROM pi_path_exception_flag WHERE path_ex_flag = DP.path_ex_flag) AS FLAG, DP.user_no, DPG.path_ex_group_name, DP.PATH_EX AS PATH, '' AS FID, DP.AP_NO AS AP_NO, (SELECT T.NAME FROM pi_targets T WHERE T.TARGET_ID = DP.TARGET_ID AND T.AP_NO = DP.AP_NO) AS HOST_NAME FROM #PI_FIND AS F pi_path_exception AS DP ,pi_path_exception_group AS DPG WHERE 1=1 AND DPG.idx = DP.path_exception_group_idx AND DPG.target_id = DP.target_id AND DPG.idx = #{group_idx}) UNION ALL (SELECT FLAG+2 AS TYPE, DP.HASH_ID AS hash_id, DP.TARGET_ID, DP.idx AS CHARGE_ID, '' AS FLAG, DP.REG_USER_NO AS user_no, DP.PATH AS path_ex_group_name, DP.PATH, '' AS FID, DP.AP_NO AS AP_NO, (SELECT T.NAME FROM pi_targets T WHERE T.TARGET_ID = DP.TARGET_ID AND T.AP_NO = DP.AP_NO) AS HOST_NAME FROM pi_charge_update AS DP WHERE 1=1 AND DP.idx = #{group_idx})) D WHERE D.TYPE = #{type}
AND D.USER_NO = #{user_no}

