mapper.select:
SELECT D.* FROM ((SELECT 1 AS TYPE, DPG.IDX AS GROUP_ID, DPCG.DATA_PROCESSING_CHARGE_ID AS CHARGE_ID, DPCG.DATA_PROCESSING_CHARGE_NAME AS CHARGE_NAME, DPG.USER_NO, (SELECT Z.USER_NAME FROM PI_USER Z WHERE Z.USER_NO = DPG.USER_NO ) AS USER_NAME, DPG.OK_USER_NO, DPG.DATA_PROCESSING_NAME, (SELECT PROCESSING_FLAG_NAME FROM PI_DATA_PROCESSING_FLAG WHERE PROCESSING_FLAG = DPG.PROCESSING_FLAG) AS FLAG, F.PATH, DPCG.REGDATE, DPCG.APPROVAL_STATUS FROM PI_FIND AS F ,PI_DATA_PROCESSING AS DP ,PI_DATA_PROCESSING_GROUP AS DPG ,PI_DATA_PROCESSING_CHARGE_GROUP AS DPCG WHERE 1=1 AND DP.TARGET_ID = F.TARGET_ID AND DP.GROUP_ID = F.GROUP_ID AND DP.HASH_ID = F.HASH_ID AND DPG.IDX = DP.DATA_PROCESSING_GROUP_IDX AND DPG.TARGET_ID = DP.TARGET_ID AND DPG.DATA_PROCESSING_CHARGE_ID = DPCG.DATA_PROCESSING_CHARGE_ID) UNION ALL (SELECT 4 AS TYPE, DPG.IDX AS GROUP_ID, DPCG.IDX AS CHARGE_ID, DPCG.PATH_EX_CHARGE_NAME AS CHARGE_NAME, DPG.user_no, (SELECT Z.USER_NAME FROM PI_USER Z WHERE Z.USER_NO = DPG.USER_NO ) AS USER_NAME, DPG.OK_USER_NO, DPG.PATH_EX_GROUP_NAME, (SELECT PATH_EX_FLAG_NAME FROM PI_PATH_EXCEPTION_FLAG WHERE PATH_EX_FLAG = DPG.PATH_EX_FLAG) AS FLAG, DP.PATH_EX AS PATH, DPCG.REGDATE, DPCG.STATUS AS APPROVAL_STATUS FROM PI_PATH_EXCEPTION AS DP ,PI_PATH_EXCEPTION_GROUP AS DPG ,PI_PATH_EXCEPTION_CHARGE AS DPCG WHERE 1=1 AND DPG.IDX = DP.PATH_EXCEPTION_GROUP_IDX AND DPG.TARGET_ID = DP.TARGET_ID AND DPG.PATH_EX_CHARGE_ID = DPCG.IDX ORDER BY DPCG.IDX DESC, DPG.idx) UNION ALL (SELECT DPCG.FLAG+2 AS TYPE, DPCG.IDX AS group_id, DPCG.IDX AS CHARGE_ID, CASE WHEN DPCG.FLAG = 0 THEN '담당자 변경' WHEN DPCG.FLAG = 1 THEN '경로 담당자 변경' END AS CHARGE_NAME, DPCG.REG_USER_NO AS user_no, (SELECT Z.USER_NAME FROM PI_USER Z WHERE Z.USER_NO = DPCG.REG_USER_NO ) AS USER_NAME, DPCG.OK_USER_NO, DPCG.path AS PATH_EX_GROUP_NAME, '' AS FLAG, DPCG.path, DPCG.REGDATE, DPCG.APPROVAL_STATUS FROM pi_charge_update AS DPCG LEFT OUTER JOIN PI_USER AS PU ON PU.USER_NO = DPCG.REG_USER_NO )) D WHERE 1=1 AND D.TYPE IN
#{item}
AND D.OK_USER_NO = #{user_no}
AND D.OK_USER_NO = #{user_no} AND D.APPROVAL_STATUS = 'W' ORDER BY D.TYPE, D.CHARGE_ID DESC

SELECT D.*, CASE WHEN D.FLAG_TYPE = 0 THEN D.REAPPROVAL_STATUS ELSE '-' END AS RESTATUS, (SELECT U.SOSOK FROM PI_USER U WHERE U.USER_NO = D.USER_NO) AS USER_SOSOK, (SELECT U.SOSOK FROM PI_USER U WHERE U.USER_NO = D.OK_USER_NO) AS OK_USER_SOSOK, F.APPROVAL_FLAG FROM ( SELECT '0' CHK, 1 AS TYPE, DPCG.data_processing_charge_id AS CHARGE_ID, DPCG.data_processing_charge_name AS PATH, '' AS HASH_ID, DPCG.USER_NO, PU.USER_NAME, DPCG.OK_USER_NO, (SELECT Z.USER_NAME FROM PI_USER Z WHERE Z.USER_NO = DPCG.ok_user_no) AS OK_USER_NAME, DATE_FORMAT(DPCG.REGDATE, '%Y-%m-%d %H:%i:%s') AS REGDATE, DATE_FORMAT(DPCG.OKDATE, '%Y-%m-%d %H:%i:%s') AS OKDATE, DPCG.APPROVAL_STATUS AS STATUS, DPCG.APPROVAL_STATUS, DPCG.REASON AS NOTE, DPCG.REAPPROVAL_STATUS, DPCG.REAPPROVAL_MEMO, (SELECT TYPE FROM pi_data_processing_flag DF WHERE (SELECT DPG.PROCESSING_FLAG FROM pi_data_processing_group DPG WHERE DPCG.DATA_PROCESSING_CHARGE_ID = DPG.DATA_PROCESSING_CHARGE_ID LIMIT 1) = DF.PROCESSING_FLAG) AS FLAG_TYPE FROM PI_DATA_PROCESSING_CHARGE_GROUP AS DPCG LEFT OUTER JOIN PI_USER AS PU ON PU.USER_NO = DPCG.USER_NO #GROUP BY DPCG.DATA_PROCESSING_CHARGE_ID #ORDER BY DPCG.REGDATE DESC, DPCG.OKDATE DESC UNION ALL SELECT '0' CHK, 4 AS TYPE, DPCG.IDX AS CHARGE_ID, DPCG.path_ex_charge_name AS PATH, '' AS HASH_ID, DPCG.USER_NO, PU.USER_NAME, DPCG.OK_USER_NO, (SELECT Z.USER_NAME FROM PI_USER Z WHERE Z.USER_NO = DPCG.ok_user_no) AS OK_USER_NAME, DATE_FORMAT(DPCG.REGDATE, '%Y-%m-%d %H:%i:%s') AS REGDATE, DATE_FORMAT(DPCG.OKDATE, '%Y-%m-%d %H:%i:%s') AS OKDATE, DPCG.STATUS, DPCG.STATUS AS APPROVAL_STATUS, DPCG.REASON AS NOTE, -1 AS REAPPROVAL_FLAG, '' AS REAPPROVAL_MEMO, -1 AS FLAG_TYPE FROM pi_path_exception_charge AS DPCG LEFT OUTER JOIN PI_USER AS PU ON PU.USER_NO = DPCG.USER_NO UNION ALL SELECT '0' CHK, DPCG.FLAG+2 AS TYPE, DPCG.IDX AS CHARGE_ID, DPCG.PATH, DPCG.HASH_ID, DPCG.REG_USER_NO, (SELECT Z.USER_NAME FROM PI_USER Z WHERE Z.USER_NO = DPCG.REG_USER_NO) AS USER_NAME, DPCG.OK_USER_NO, (SELECT Z.USER_NAME FROM PI_USER Z WHERE Z.USER_NO = DPCG.ok_user_no) AS OK_USER_NAME, DATE_FORMAT(DPCG.REGDATE, '%Y-%m-%d %H:%i:%s') AS REGDATE, DATE_FORMAT(DPCG.OKDATE, '%Y-%m-%d %H:%i:%s') AS OKDATE, DPCG.APPROVAL_STATUS AS STATUS, DPCG.APPROVAL_STATUS, DPCG.REASON AS NOTE, -1 AS REAPPROVAL_FLAG, '' AS REAPPROVAL_MEMO, -1 AS FLAG_TYPE FROM pi_charge_update AS DPCG WHERE 1 = 1 ) D LEFT OUTER JOIN pi_approval_flag F ON F.idx = D.TYPE WHERE 1=1
AND D.APPROVAL_STATUS = #{status}
AND DATE_FORMAT(D.REGDATE, '%Y-%m-%d') BETWEEN DATE_FORMAT(#{fromDate}, '%Y-%m-%d') AND DATE_FORMAT(#{toDate}, '%Y-%m-%d')
AND D.USER_NAME LIKE CONCAT('%',#{user_nm},'%')
AND D.PATH LIKE CONCAT('%',#{path},'%')
AND (D.USER_NO = #{user_no} OR D.OK_USER_NO = #{user_no} )
AND D.TYPE IN (
#{item}
