SELECT D.TARGET_ID, D.NAME, COUNT(D.PROCESSING_FLAG) AS RESULT_CNT, D.PROCESSING_FLAG_NAME FROM (SELECT DP.TARGET_ID, T.NAME, DP.DATA_PROCESSING_GROUP_IDX, DP.PROCESSING_FLAG, DF.PROCESSING_FLAG_NAME FROM pi_data_processing AS DP, pi_targets T, pi_data_processing_flag DF WHERE 1 = 1 AND DP.data_processing_group_idx IN
#{item}
AND T.TARGET_ID = DP.TARGET_ID AND T.AP_NO = DP.AP_NO AND DF.PROCESSING_FLAG = DP.PROCESSING_FLAG) AS D GROUP BY D.TARGET_ID, D.PROCESSING_FLAG ORDER BY D.NAME

