UPDATE PI_FIND SET
	OWNER = #{UPDATE_OWNER}
	WHERE TARGET_ID = #{TARGET_ID}
	AND AP_NO = #{AP_NO}
	AND HASH_ID = #{HASH_ID}

UPDATE pi_data_processing_charge_group  
	SET reapproval_status = #{reapproval_status},
	approval_status = #{reapproval_status},
	reapproval_memo = #{reapproval_memo}
	WHERE DATA_PROCESSING_CHARGE_ID = #{idx};

	UPDATE pi_data_processing_group  
		SET reapproval_status = #{reapproval_status},
		approval_status = #{reapproval_status}
	WHERE IDX = #{group_id};

	UPDATE PI_DATA_PROCESSING
		SET reapproval_status = #{reapproval_status},
		approval_status = #{reapproval_status}
	WHERE data_processing_group_idx = #{group_id};


    	UPDATE pi_find F, (SELECT D.DATA_PROCESSING_IDX AS IDX, D.TARGET_ID, D.AP_NO, D.HASH_ID FROM pi_data_processing D WHERE D.data_processing_group_idx = #{group_id}) D
		SET F.APPROVAL_ID = D.IDX,
		 F.APPROVAL_FLAG = 0,
		 F.REMEDIATION_STATUS =  'False Match'
		WHERE F.TARGET_ID = D.TARGET_ID
		  AND F.AP_NO = D.AP_NO
		  AND F.HASH_ID = D.HASH_ID
		  AND F.HASH_ID = #{hash_id}
